def emit(mob: str, variants: dict[str, str]) -> dict[str, str]:
    out = {}
    for k, v in variants.items():
        out[f"naturalmobdrops:{mob}/{k}"] = v
    return out


def load_zombie_flat() -> dict[str, str]:
    if not ZOMBIE_SRC.is_file():
        print("WARN: missing", ZOMBIE_SRC, "- run scripts download or place momh_zombie_villager.json")
        return {}
    z = json.loads(ZOMBIE_SRC.read_text(encoding="utf-8"))
    out = {}
    root = z["heads"]["zombie_villager"]
    for biome, profs in root.items():
        if not isinstance(profs, dict):
            continue
        for prof, data in profs.items():
            if isinstance(data, dict) and "texture" in data:
                out[f"naturalmobdrops:zombie_villager/{biome}/{prof}"] = data["texture"]
    return out


textures = {}
for mob, d in [
    ("horse", HORSE),
    ("axolotl", AXO),
    ("chicken", CHICKEN),
    ("pig", PIG),
    ("cow", COW),
    ("cat", CAT),
    ("wolf", WOLF),
    ("panda", PANDA),
    ("frog", FROG),
    ("fox", FOX),
    ("rabbit", RABBIT),
    ("parrot", PARROT),
    ("mooshroom", MOOSHROOM),
    ("salmon", SALMON),
    ("tropical_fish", TROPICAL_FISH),
    ("llama", LLAMA),
    ("trader_llama", TRADER_LLAMA),
]:
    textures.update(emit(mob, d))

textures.update(load_zombie_flat())

textures["naturalmobdrops:cat/original"] = CAT["tabby"]
textures["naturalmobdrops:wolf/original"] = WOLF["pale"]
textures["naturalmobdrops:panda/original"] = PANDA["normal"]
textures["naturalmobdrops:frog/original"] = FROG["temperate"]
textures["naturalmobdrops:fox/original"] = FOX["red"]
textures["naturalmobdrops:rabbit/original"] = RABBIT["brown"]
textures["naturalmobdrops:parrot/original"] = PARROT["red"]
textures["naturalmobdrops:mooshroom/original"] = MOOSHROOM["red"]
textures["naturalmobdrops:salmon/original"] = SALMON_TEX
textures["naturalmobdrops:tropical_fish/original"] = TROPICAL_FISH["tropical_fish"]
textures["naturalmobdrops:llama/original"] = LLAMA["creamy"]
textures["naturalmobdrops:trader_llama/original"] = TRADER_LLAMA["creamy"]
_zk = "naturalmobdrops:zombie_villager/plains/none"
if _zk in textures:
    textures["naturalmobdrops:zombie_villager/original"] = textures[_zk]

out = {"textures": textures}
ROOT.mkdir(parents=True, exist_ok=True)
path = ROOT / "builtin_variant_mob_heads.json"
path.write_text(json.dumps(out, indent=2) + "\n", encoding="utf-8")
print(path, "keys", len(textures))
